import { KnowledgeArticle, CK, nextId } from "./types"

type Seed = [string, string[], string, string]

function gen(seeds: Seed[], catKey: string, author: string, dateRange: [string, string]): KnowledgeArticle[] {
  const [d0, d1] = dateRange
  const t0 = new Date(d0).getTime()
  const t1 = new Date(d1).getTime()
  return seeds.map((s, i) => {
    const ts = t0 + ((i / seeds.length) * (t1 - t0))
    const d = new Date(ts).toISOString().split("T")[0]
    return {
      id: nextId(),
      title: s[0],
      categoryKey: catKey,
      date: d,
      citedByAI: Math.floor(Math.random() * 45) + 1,
      author,
      tags: s[1],
      summary: s[2],
      content: s[3],
    }
  })
}

